import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            int found = 0;
            for (int i = 0; i < n; i++) {
                int count = 0;
                for (int j = i; j < n; j++) {
                    if (a[j] % 2 == 0) {
                        count++;
                    }
                    if (count == k) {
                        found = 1;
                        break;
                    }
                }
                if (found == 1) {
                    break;
                }
            }
            if (found == 1) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

